# Complete Genomics var-ASM format:
# - Two rows per diploid variant (one per allele)
# - 0-based half-open coordinates (begin+1 = 1-based position)
# - rsIDs in xRef column as "dbsnp.NNN:rsXXXXXX"
# Locus 10: homozygous alt T/T (both alleles are SNP)
# Locus 20: het allele1=A (SNP), allele2=ref G (no SNP row)
# Locus 30: het allele1=ref A (no SNP row), allele2=G (SNP)
# Locus 40: VQLOW — should be filtered out
SAMPLE_CGI = """\
#ASSEMBLY_ID\tGS00253-DNA_A01_200_37-ASM
#GENOME_REFERENCE\tNCBI build 37
#TYPE\tVAR-ANNOTATION
\t\t\t\t\t\t\t\t\t\t\t\t\t
>locus\tploidy\tallele\tchromosome\tbegin\tend\tvarType\treference\talleleSeq\tvarScoreVAF\tvarScoreEAF\tvarQuality\thapLink\txRef
10\t2\t1\tchr1\t21579\t21580\tsnp\tC\tT\t100\t100\tVQHIGH\t\tdbsnp.83:rs526642
10\t2\t2\tchr1\t21579\t21580\tsnp\tC\tT\t135\t135\tVQHIGH\t\tdbsnp.83:rs526642
20\t2\t1\tchr1\t23974\t23975\tsnp\tG\tA\t58\t58\tVQHIGH\t\tdbsnp.100:rs2748067;dbsnp.131:rs76046194
30\t2\t2\tchr19\t38231\t38232\tsnp\tA\tG\t112\t112\tVQHIGH\t\tdbsnp.86:rs806727
40\t2\t1\tchr1\t46669\t46670\tsnp\tA\tG\t45\t45\tVQLOW\t\tdbsnp.100:rs2548905
"""


# ---------------------------------------------------------------------------
# Format detection
# ---------------------------------------------------------------------------

class TestDetectFormat:
    def test_detects_23andme(self):
        lines = SAMPLE_23ANDME.split("\n")[:10]
        assert detect_format(lines) == "23andme"

    def test_detects_ancestrydna(self):
        lines = SAMPLE_ANCESTRYDNA.split("\n")[:10]
        assert detect_format(lines) == "ancestrydna"

    def test_detects_vcf(self):
        lines = SAMPLE_VCF.split("\n")[:10]
        assert detect_format(lines) == "vcf"

    def test_detects_cgi(self):
        lines = SAMPLE_CGI.split("\n")[:10]
        assert detect_format(lines) == "cgi"

    def test_raises_on_unknown(self):
        with pytest.raises(ParseError):
            detect_format(["some random text", "with no structure"])


# ---------------------------------------------------------------------------
# 23andMe parser
# ---------------------------------------------------------------------------

class TestParse23andMe:
    def test_basic_parsing(self):
        df = parse_23andme(SAMPLE_23ANDME)
        assert len(df) == 6
        assert df.columns == ["rsid", "chrom", "position", "allele1", "allele2"]

    def test_specific_variant(self):
        df = parse_23andme(SAMPLE_23ANDME)
        row = df.filter(pl.col("rsid") == "rs3094315")
        assert row["allele1"][0] == "A"
        assert row["allele2"][0] == "G"
        assert row["chrom"][0] == "1"
        assert row["position"][0] == 752566

    def test_homozygous(self):
        df = parse_23andme(SAMPLE_23ANDME)
        row = df.filter(pl.col("rsid") == "rs4477212")
        assert row["allele1"][0] == "A"
        assert row["allele2"][0] == "A"

    def test_filters_nocalls(self):
        df = parse_23andme(SAMPLE_23ANDME_WITH_NOCALLS)
        assert len(df) == 2
        rsids = df["rsid"].to_list()
        assert "rs4477212" in rsids
        assert "rs3094315" in rsids

    def test_haploid_genotype(self):
        df = parse_23andme(SAMPLE_23ANDME_HAPLOID)
        assert len(df) == 2
        row = df.filter(pl.col("rsid") == "rs4477212")
        assert row["allele1"][0] == "A"
        assert row["allele2"][0] == "A"

    def test_empty_file_raises(self):
        with pytest.raises(ParseError):
            parse_23andme("# comment only\n")

    def test_dtypes(self):
        df = parse_23andme(SAMPLE_23ANDME)
        assert df.schema["rsid"] == pl.Utf8
        assert df.schema["chrom"] == pl.Utf8
        assert df.schema["position"] == pl.Int64
        assert df.schema["allele1"] == pl.Utf8
        assert df.schema["allele2"] == pl.Utf8


