# ---------------------------------------------------------------------------
# VCF parser
# ---------------------------------------------------------------------------

class TestParseVCF:
    def test_basic_parsing(self):
        df = parse_vcf(SAMPLE_VCF)
        assert len(df) == 3

    def test_homref(self):
        df = parse_vcf(SAMPLE_VCF)
        row = df.filter(pl.col("rsid") == "rs4477212")
        assert row["allele1"][0] == "A"
        assert row["allele2"][0] == "A"

    def test_het(self):
        df = parse_vcf(SAMPLE_VCF)
        row = df.filter(pl.col("rsid") == "rs3094315")
        assert row["allele1"][0] == "A"
        assert row["allele2"][0] == "G"

    def test_homalt(self):
        df = parse_vcf(SAMPLE_VCF)
        row = df.filter(pl.col("rsid") == "rs3131972")
        assert row["allele1"][0] == "G"
        assert row["allele2"][0] == "G"

    def test_phased_genotype(self):
        df = parse_vcf(SAMPLE_VCF_PHASED)
        assert len(df) == 1
        row = df.row(0, named=True)
        assert row["allele1"] == "A"
        assert row["allele2"] == "G"
        # chr prefix should be stripped
        assert row["chrom"] == "1"

    def test_skips_multiallelic(self):
        df = parse_vcf(SAMPLE_VCF_MULTIALLELIC)
        assert len(df) == 1
        assert df["rsid"][0] == "rs3094315"

    def test_haploid_hemizygous_alt(self):
        """Hemizygous ALT on chrX (e.g. rs6323 MAOA in males) should be duplicated."""
        df = parse_vcf(SAMPLE_VCF_HAPLOID)
        row = df.filter(pl.col("rsid") == "rs6323")
        assert len(row) == 1
        assert row["allele1"][0] == "T"
        assert row["allele2"][0] == "T"
        assert row["chrom"][0] == "X"

    def test_haploid_hemizygous_ref(self):
        """Hemizygous REF on chrX should be duplicated."""
        df = parse_vcf(SAMPLE_VCF_HAPLOID)
        row = df.filter(pl.col("rsid") == "rs99999")
        assert len(row) == 1
        assert row["allele1"][0] == "C"
        assert row["allele2"][0] == "C"

    def test_haploid_mixed_with_diploid(self):
        """Haploid and diploid calls in same VCF should both be parsed."""
        df = parse_vcf(SAMPLE_VCF_HAPLOID)
        assert len(df) == 3  # 2 haploid + 1 diploid

    def test_empty_file_raises(self):
        with pytest.raises(ParseError):
            parse_vcf("##fileformat=VCFv4.1\n#CHROM\tPOS\tID\n")


# ---------------------------------------------------------------------------
# Complete Genomics parser
# ---------------------------------------------------------------------------

class TestParseCGI:
    def test_basic_parsing(self):
        df = parse_cgi(SAMPLE_CGI)
        assert df.columns == ["rsid", "chrom", "position", "allele1", "allele2"]
        # 3 variants: locus 10 (hom), locus 20 (het a1), locus 30 (het a2)
        # Locus 40 filtered out (VQLOW)
        assert len(df) == 3

    def test_homozygous_alt(self):
        """Locus 10: both alleles are SNP T (ref C)."""
        df = parse_cgi(SAMPLE_CGI)
        row = df.filter(pl.col("rsid") == "rs526642")
        assert row["allele1"][0] == "T"
        assert row["allele2"][0] == "T"

    def test_het_allele1_only(self):
        """Locus 20: only allele 1 is a SNP (A), allele 2 should be ref (G)."""
        df = parse_cgi(SAMPLE_CGI)
        row = df.filter(pl.col("rsid") == "rs2748067")
        assert row["allele1"][0] == "A"
        assert row["allele2"][0] == "G"

    def test_het_allele2_only(self):
        """Locus 30: only allele 2 is a SNP (G), allele 1 should be ref (A)."""
        df = parse_cgi(SAMPLE_CGI)
        row = df.filter(pl.col("rsid") == "rs806727")
        assert row["allele1"][0] == "A"
        assert row["allele2"][0] == "G"

    def test_filters_vqlow(self):
        """Locus 40 is VQLOW and should be excluded."""
        df = parse_cgi(SAMPLE_CGI)
        assert df.filter(pl.col("rsid") == "rs2548905").height == 0

    def test_position_conversion(self):
        """CGI 0-based begin=21579 should become 1-based position=21580."""
        df = parse_cgi(SAMPLE_CGI)
        row = df.filter(pl.col("rsid") == "rs526642")
        assert row["position"][0] == 21580

    def test_chr_prefix_stripped(self):
        df = parse_cgi(SAMPLE_CGI)
        row = df.filter(pl.col("rsid") == "rs806727")
        assert row["chrom"][0] == "19"

    def test_extracts_first_rsid_from_multi(self):
        """xRef with multiple dbsnp entries should extract the first rsID."""
        df = parse_cgi(SAMPLE_CGI)
        # Locus 20 has "dbsnp.100:rs2748067;dbsnp.131:rs76046194"
        assert df.filter(pl.col("rsid") == "rs2748067").height == 1

    def test_empty_file_raises(self):
        with pytest.raises(ParseError):
            parse_cgi("#TYPE\tVAR-ANNOTATION\n>locus\tploidy\tallele\n")

    def test_dtypes(self):
        df = parse_cgi(SAMPLE_CGI)
        assert df.schema["rsid"] == pl.Utf8
        assert df.schema["chrom"] == pl.Utf8
        assert df.schema["position"] == pl.Int64
        assert df.schema["allele1"] == pl.Utf8
        assert df.schema["allele2"] == pl.Utf8


# ---------------------------------------------------------------------------
# Chip version detection
# ---------------------------------------------------------------------------

class TestDetectChipVersion:
    def test_23andme_v5(self):
        assert detect_chip_version(950_000) == "23andme_v5"

    def test_ancestrydna_v2(self):
        assert detect_chip_version(350_000) == "ancestrydna_v2"

    def test_unknown(self):
        assert detect_chip_version(50) == "unknown"


# ---------------------------------------------------------------------------
# Integration: parse_genotype_file
# ---------------------------------------------------------------------------

class TestParseGenotypeFile:
    def test_23andme_integration(self):
        df, fmt, chip = parse_genotype_file(SAMPLE_23ANDME)
        assert fmt == "23andme"
        assert len(df) == 6
        assert chip == "unknown"  # too few variants for chip detection

    def test_ancestrydna_integration(self):
        df, fmt, chip = parse_genotype_file(SAMPLE_ANCESTRYDNA)
        assert fmt == "ancestrydna"
        assert len(df) == 4

    def test_vcf_integration(self):
        df, fmt, chip = parse_genotype_file(SAMPLE_VCF)
        assert fmt == "vcf"
        assert len(df) == 3

    def test_cgi_integration(self):
        df, fmt, chip = parse_genotype_file(SAMPLE_CGI)
        assert fmt == "cgi"
        assert len(df) == 3

    def test_filters_indels_from_23andme(self):
        content = """\
# rsid\tchromosome\tposition\tgenotype
rs100\t1\t100\tAG
rs200\t1\t200\tDI
rs300\t1\t300\tAA
"""
        df, fmt, _ = parse_genotype_file(content)
        assert len(df) == 2
